// // This module synchronously resets the output 'c' to the value of input 'a' on the falling edge of the clock 'clk'. When 'reset' is high, 'c' remains unchanged.
module top_module(clk,reset,a,c);input clk;
   input reset;
   input a; 
   output c; 

   wire clk;
   wire reset;   
   wire a;   
   reg c;

always @ (posedge clk )
  if ( reset == 1'b1) begin
    c <= 0;
  end else begin
    c <= a;
  end

endmodule
